import{_ as a,c as n,o as e,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"コマンド: 監視とプルーニング | opencode-dynamic-context-pruning","description":"DCP の 4 つのコマンドで監視と手動プルーニングを学びます。/dcp context でセッション確認、/dcp stats で統計表示、/dcp sweep で手動プルーニングをトリガーする方法を解説。","frontmatter":{"title":"コマンド: 監視とプルーニング | opencode-dynamic-context-pruning","sidebarTitle":"トークン監視・手動プルーニング","subtitle":"DCP コマンド使用ガイド：監視と手動プルーニング","description":"DCP の 4 つのコマンドで監視と手動プルーニングを学びます。/dcp context でセッション確認、/dcp stats で統計表示、/dcp sweep で手動プルーニングをトリガーする方法を解説。","tags":["DCP コマンド","トークン監視","手動プルーニング"],"prerequisite":["start-getting-started","platforms-auto-pruning"],"order":3},"headers":[],"relativePath":"ja/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md","filePath":"ja/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"}'),o={name:"ja/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"};function p(d,s,l,c,i,r){return e(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="dcp-コマンド使用ガイド-監視と手動プルーニング" tabindex="-1">DCP コマンド使用ガイド：監視と手動プルーニング <a class="header-anchor" href="#dcp-コマンド使用ガイド-監視と手動プルーニング" aria-label="Permalink to &quot;DCP コマンド使用ガイド：監視と手動プルーニング&quot;">​</a></h1><h2 id="このレッスンで学べること" tabindex="-1">このレッスンで学べること <a class="header-anchor" href="#このレッスンで学べること" aria-label="Permalink to &quot;このレッスンで学べること&quot;">​</a></h2><ul><li><code>/dcp context</code> で現在のセッションのトークン使用分布を確認する</li><li><code>/dcp stats</code> で累計プルーニング統計を表示する</li><li><code>/dcp sweep [n]</code> で手動プルーニングをトリガーする</li><li>保護対象ツールとファイルの保護メカニズムを理解する</li><li>トークン計算戦略と節約効果を把握する</li></ul><h2 id="今あなたが直面している課題" tabindex="-1">今あなたが直面している課題 <a class="header-anchor" href="#今あなたが直面している課題" aria-label="Permalink to &quot;今あなたが直面している課題&quot;">​</a></h2><p>長い会話の中で、トークン消費がどんどん増えていきますが、以下のことがわかりません：</p><ul><li>現在のセッションでトークンはどこに使われているのか？</li><li>DCP は実際にどれくらい節約してくれているのか？</li><li>不要になったツール出力を手動でクリアするにはどうすればいいのか？</li><li>どのツールが保護され、プルーニングされないのか？</li></ul><p>これらの疑問を解決しないと、DCP の最適化効果を十分に活用できず、重要な情報を誤って削除してしまう可能性もあります。</p><h2 id="このテクニックを使うタイミング" tabindex="-1">このテクニックを使うタイミング <a class="header-anchor" href="#このテクニックを使うタイミング" aria-label="Permalink to &quot;このテクニックを使うタイミング&quot;">​</a></h2><p>以下のような場合に使用します：</p><ul><li>現在のセッションのトークン構成を把握したいとき</li><li>会話履歴を素早くクリアしたいとき</li><li>DCP のプルーニング効果を検証したいとき</li><li>新しいタスクを開始する前にコンテキストを整理したいとき</li></ul><h2 id="基本的な考え方" tabindex="-1">基本的な考え方 <a class="header-anchor" href="#基本的な考え方" aria-label="Permalink to &quot;基本的な考え方&quot;">​</a></h2><p>DCP は 4 つの Slash コマンドを提供し、トークン使用の監視と制御を支援します：</p><table tabindex="0"><thead><tr><th>コマンド</th><th>用途</th><th>使用シーン</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>ヘルプを表示</td><td>コマンドを忘れたときに確認</td></tr><tr><td><code>/dcp context</code></td><td>現在のセッションのトークン分布を分析</td><td>コンテキスト構成の把握</td></tr><tr><td><code>/dcp stats</code></td><td>累計プルーニング統計を表示</td><td>長期的な効果の検証</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>手動でツールをプルーニング</td><td>コンテキストサイズの素早い削減</td></tr></tbody></table><p><strong>保護メカニズム</strong>：</p><p>すべてのプルーニング操作は以下を自動的にスキップします：</p><ul><li><strong>保護対象ツール</strong>：<code>task</code>、<code>todowrite</code>、<code>todoread</code>、<code>discard</code>、<code>extract</code>、<code>batch</code>、<code>write</code>、<code>edit</code>、<code>plan_enter</code>、<code>plan_exit</code></li><li><strong>保護対象ファイル</strong>：設定の <code>protectedFilePatterns</code> にマッチするファイルパス</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>保護対象ツールと保護対象ファイルの設定は、設定ファイルでカスタマイズできます。詳細は<a href="./../../start/configuration/">設定完全ガイド</a>を参照してください。</p></div><h2 id="実践してみよう" tabindex="-1">実践してみよう <a class="header-anchor" href="#実践してみよう" aria-label="Permalink to &quot;実践してみよう&quot;">​</a></h2><h3 id="ステップ-1-ヘルプ情報を確認する" tabindex="-1">ステップ 1：ヘルプ情報を確認する <a class="header-anchor" href="#ステップ-1-ヘルプ情報を確認する" aria-label="Permalink to &quot;ステップ 1：ヘルプ情報を確認する&quot;">​</a></h3><p>OpenCode の対話ボックスで <code>/dcp</code> と入力します。</p><p><strong>表示される内容</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Commands                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /dcp context      Show token usage breakdown for current session</span></span>
<span class="line"><span>  /dcp stats        Show DCP pruning statistics</span></span>
<span class="line"><span>  /dcp sweep [n]    Prune tools since last user message, or last n tools</span></span></code></pre></div><p><strong>チェックポイント ✅</strong>：3 つのサブコマンドの説明が表示されていることを確認します。</p><h3 id="ステップ-2-現在のセッションのトークン分布を分析する" tabindex="-1">ステップ 2：現在のセッションのトークン分布を分析する <a class="header-anchor" href="#ステップ-2-現在のセッションのトークン分布を分析する" aria-label="Permalink to &quot;ステップ 2：現在のセッションのトークン分布を分析する&quot;">​</a></h3><p><code>/dcp context</code> と入力して、現在のセッションのトークン使用状況を確認します。</p><p><strong>表示される内容</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                  DCP Context Analysis                     │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session Context Breakdown:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System         15.2% │████████████████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│  25.1K tokens</span></span>
<span class="line"><span>User            5.1% │████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│   8.4K tokens</span></span>
<span class="line"><span>Assistant       35.8% │██████████████████████████████████████▒▒▒▒▒▒▒│  59.2K tokens</span></span>
<span class="line"><span>Tools (45)      43.9% │████████████████████████████████████████████████│  72.6K tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary:</span></span>
<span class="line"><span>  Pruned:          12 tools (~15.2K tokens)</span></span>
<span class="line"><span>  Current context: ~165.3K tokens</span></span>
<span class="line"><span>  Without DCP:     ~180.5K tokens</span></span></code></pre></div><p><strong>トークン分類の説明</strong>：</p><table tabindex="0"><thead><tr><th>分類</th><th>計算方法</th><th>説明</th></tr></thead><tbody><tr><td><strong>System</strong></td><td><code>firstAssistant.input + cache.read - tokenizer(firstUserMessage)</code></td><td>システムプロンプト</td></tr><tr><td><strong>Tools</strong></td><td><code>tokenizer(toolInputs + toolOutputs) - prunedTokens</code></td><td>ツール呼び出し（プルーニング分を差し引き済み）</td></tr><tr><td><strong>User</strong></td><td><code>tokenizer(all user messages)</code></td><td>すべてのユーザーメッセージ</td></tr><tr><td><strong>Assistant</strong></td><td><code>total - system - user - tools</code></td><td>AI テキスト出力 + 推論トークン</td></tr></tbody></table><p><strong>チェックポイント ✅</strong>：各分類のトークン割合と数量が表示されていることを確認します。</p><h3 id="ステップ-3-累計プルーニング統計を確認する" tabindex="-1">ステップ 3：累計プルーニング統計を確認する <a class="header-anchor" href="#ステップ-3-累計プルーニング統計を確認する" aria-label="Permalink to &quot;ステップ 3：累計プルーニング統計を確認する&quot;">​</a></h3><p><code>/dcp stats</code> と入力して、過去の累計プルーニング効果を確認します。</p><p><strong>表示される内容</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                    DCP Statistics                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens pruned: ~15.2K</span></span>
<span class="line"><span>  Tools pruned:   12</span></span>
<span class="line"><span></span></span>
<span class="line"><span>All-time:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens saved:  ~284.5K</span></span>
<span class="line"><span>  Tools pruned:   156</span></span>
<span class="line"><span>  Sessions:       8</span></span></code></pre></div><p><strong>統計の説明</strong>：</p><ul><li><strong>Session</strong>：現在のセッションのプルーニングデータ（メモリ内）</li><li><strong>All-time</strong>：すべての過去セッションの累計データ（ディスクに永続化）</li></ul><p><strong>チェックポイント ✅</strong>：現在のセッションと過去の累計プルーニング統計が表示されていることを確認します。</p><h3 id="ステップ-4-手動でツールをプルーニングする" tabindex="-1">ステップ 4：手動でツールをプルーニングする <a class="header-anchor" href="#ステップ-4-手動でツールをプルーニングする" aria-label="Permalink to &quot;ステップ 4：手動でツールをプルーニングする&quot;">​</a></h3><p><code>/dcp sweep</code> の使い方は 2 通りあります：</p><h4 id="方法-1-前回のユーザーメッセージ以降のすべてのツールをプルーニング" tabindex="-1">方法 1：前回のユーザーメッセージ以降のすべてのツールをプルーニング <a class="header-anchor" href="#方法-1-前回のユーザーメッセージ以降のすべてのツールをプルーニング" aria-label="Permalink to &quot;方法 1：前回のユーザーメッセージ以降のすべてのツールをプルーニング&quot;">​</a></h4><p><code>/dcp sweep</code>（引数なし）と入力します。</p><p><strong>表示される内容</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept 8 tool(s) since previous user message.</span></span>
<span class="line"><span>Tokens saved: ~12,345</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/config.ts</span></span>
<span class="line"><span>  • Read: src/utils.ts</span></span>
<span class="line"><span>  • Bash: npm test</span></span>
<span class="line"><span>  • Read: package.json</span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span></code></pre></div><h4 id="方法-2-最後の-n-個のツールをプルーニング" tabindex="-1">方法 2：最後の N 個のツールをプルーニング <a class="header-anchor" href="#方法-2-最後の-n-個のツールをプルーニング" aria-label="Permalink to &quot;方法 2：最後の N 個のツールをプルーニング&quot;">​</a></h4><p><code>/dcp sweep 5</code> と入力して、最後の 5 個のツールをプルーニングします。</p><p><strong>表示される内容</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept last 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span>
<span class="line"><span>  • Bash: npm run build</span></span></code></pre></div><p><strong>保護対象ツールの通知</strong>：</p><p>保護対象ツールがスキップされた場合、出力に以下が表示されます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Swept 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span>(2 protected tool(s) skipped)</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>保護対象ツール（<code>write</code>、<code>edit</code> など）と保護対象ファイルパスは自動的にスキップされ、プルーニングされません。</p></div><p><strong>チェックポイント ✅</strong>：プルーニングされたツールのリストと節約されたトークン数が表示されていることを確認します。</p><h3 id="ステップ-5-プルーニング効果を再確認する" tabindex="-1">ステップ 5：プルーニング効果を再確認する <a class="header-anchor" href="#ステップ-5-プルーニング効果を再確認する" aria-label="Permalink to &quot;ステップ 5：プルーニング効果を再確認する&quot;">​</a></h3><p>プルーニング後、再度 <code>/dcp context</code> と入力して、新しいトークン分布を確認します。</p><p><strong>表示される内容</strong>：</p><ul><li><code>Tools</code> 分類の割合が減少</li><li><code>Summary</code> にプルーニングされたツール数の増加が表示</li><li><code>Current context</code> の合計が減少</li></ul><p><strong>チェックポイント ✅</strong>：トークン使用量が明らかに減少していることを確認します。</p><h2 id="よくある失敗パターン" tabindex="-1">よくある失敗パターン <a class="header-anchor" href="#よくある失敗パターン" aria-label="Permalink to &quot;よくある失敗パターン&quot;">​</a></h2><h3 id="❌-失敗例-重要なツールを誤って削除" tabindex="-1">❌ 失敗例：重要なツールを誤って削除 <a class="header-anchor" href="#❌-失敗例-重要なツールを誤って削除" aria-label="Permalink to &quot;❌ 失敗例：重要なツールを誤って削除&quot;">​</a></h3><p><strong>シナリオ</strong>：<code>write</code> ツールで重要なファイルを作成した直後に <code>/dcp sweep</code> を実行。</p><p><strong>誤った結果</strong>：<code>write</code> ツールがプルーニングされ、AI がファイルの作成を認識できなくなる。</p><p><strong>正しい対処法</strong>：</p><ul><li><code>write</code>、<code>edit</code> などのツールはデフォルトで保護されている</li><li><code>protectedTools</code> 設定からこれらのツールを削除しない</li><li>重要なタスク完了後は数ターン待ってからクリアする</li></ul><h3 id="❌-失敗例-不適切なタイミングでのプルーニング" tabindex="-1">❌ 失敗例：不適切なタイミングでのプルーニング <a class="header-anchor" href="#❌-失敗例-不適切なタイミングでのプルーニング" aria-label="Permalink to &quot;❌ 失敗例：不適切なタイミングでのプルーニング&quot;">​</a></h3><p><strong>シナリオ</strong>：会話が始まったばかりで、ツール呼び出しが数回しかない状態で <code>/dcp sweep</code> を実行。</p><p><strong>誤った結果</strong>：節約されるトークンが少なく、むしろコンテキストの一貫性に影響を与える可能性がある。</p><p><strong>正しい対処法</strong>：</p><ul><li>会話がある程度進んでから（例：10 回以上のツール呼び出し後）クリアする</li><li>新しいタスクを開始する前に、前回のツール出力をクリアする</li><li><code>/dcp context</code> と組み合わせて、クリアする価値があるかどうかを判断する</li></ul><h3 id="❌-失敗例-手動プルーニングへの過度な依存" tabindex="-1">❌ 失敗例：手動プルーニングへの過度な依存 <a class="header-anchor" href="#❌-失敗例-手動プルーニングへの過度な依存" aria-label="Permalink to &quot;❌ 失敗例：手動プルーニングへの過度な依存&quot;">​</a></h3><p><strong>シナリオ</strong>：毎回の会話で手動で <code>/dcp sweep</code> を実行。</p><p><strong>誤った結果</strong>：</p><ul><li>自動プルーニング戦略（重複排除、上書き書き込み、エラークリア）が無駄になる</li><li>操作の負担が増加</li></ul><p><strong>正しい対処法</strong>：</p><ul><li>自動プルーニング戦略をデフォルトで有効にする（設定：<code>strategies.*.enabled</code>）</li><li>手動プルーニングは補助として、必要なときのみ使用する</li><li><code>/dcp stats</code> で自動プルーニングの効果を検証する</li></ul><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><p>DCP の 4 つのコマンドは、トークン使用の監視と制御を支援します：</p><table tabindex="0"><thead><tr><th>コマンド</th><th>主な機能</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>ヘルプ情報を表示</td></tr><tr><td><code>/dcp context</code></td><td>現在のセッションのトークン分布を分析</td></tr><tr><td><code>/dcp stats</code></td><td>累計プルーニング統計を表示</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>手動でツールをプルーニング</td></tr></tbody></table><p><strong>トークン計算戦略</strong>：</p><ul><li>System：システムプロンプト（最初のレスポンスから推算）</li><li>Tools：ツールの入出力（プルーニング分を差し引き）</li><li>User：すべてのユーザーメッセージ（推定）</li><li>Assistant：AI 出力 + 推論トークン（残差）</li></ul><p><strong>保護メカニズム</strong>：</p><ul><li>保護対象ツール：<code>task</code>、<code>todowrite</code>、<code>todoread</code>、<code>discard</code>、<code>extract</code>、<code>batch</code>、<code>write</code>、<code>edit</code>、<code>plan_enter</code>、<code>plan_exit</code></li><li>保護対象ファイル：設定された glob パターン</li><li>すべてのプルーニング操作はこれらのコンテンツを自動的にスキップ</li></ul><p><strong>ベストプラクティス</strong>：</p><ul><li>定期的に <code>/dcp context</code> でトークン構成を確認する</li><li>新しいタスクの前に <code>/dcp sweep</code> で履歴をクリアする</li><li>自動プルーニングに依存し、手動プルーニングは補助として使用する</li><li><code>/dcp stats</code> で長期的な効果を検証する</li></ul><h2 id="次のレッスンの予告" tabindex="-1">次のレッスンの予告 <a class="header-anchor" href="#次のレッスンの予告" aria-label="Permalink to &quot;次のレッスンの予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../../advanced/protection/">保護メカニズム</a></strong> を学びます。</p><p>学べる内容：</p><ul><li>ターン保護が誤プルーニングを防ぐ仕組み</li><li>保護対象ツールリストのカスタマイズ方法</li><li>保護対象ファイルパターンの設定方法</li><li>サブエージェントセッションの特別な処理</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>/dcp ヘルプコマンド</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/help.ts" target="_blank" rel="noreferrer"><code>lib/commands/help.ts</code></a></td><td>19-32</td></tr><tr><td>/dcp context コマンド</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>238-247</td></tr><tr><td>トークン計算戦略</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>5-38</td></tr><tr><td>/dcp stats コマンド</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/stats.ts" target="_blank" rel="noreferrer"><code>lib/commands/stats.ts</code></a></td><td>46-67</td></tr><tr><td>/dcp sweep コマンド</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/sweep.ts" target="_blank" rel="noreferrer"><code>lib/commands/sweep.ts</code></a></td><td>123-259</td></tr><tr><td>保護対象ツール設定</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/config.ts" target="_blank" rel="noreferrer"><code>lib/config.ts</code></a></td><td>461</td></tr><tr><td>デフォルト保護対象ツールリスト</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/README.md" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>150-151</td></tr></tbody></table><p><strong>主要な定数</strong>：</p><ul><li><code>DEFAULT_PROTECTED_TOOLS</code>：デフォルトの保護対象ツールリスト</li></ul><p><strong>主要な関数</strong>：</p><ul><li><code>handleHelpCommand()</code>：/dcp ヘルプコマンドを処理</li><li><code>handleContextCommand()</code>：/dcp context コマンドを処理</li><li><code>analyzeTokens()</code>：各カテゴリのトークン数を計算</li><li><code>handleStatsCommand()</code>：/dcp stats コマンドを処理</li><li><code>handleSweepCommand()</code>：/dcp sweep コマンドを処理</li><li><code>buildToolIdList()</code>：ツール ID リストを構築</li></ul></details>`,88)])])}const g=a(o,[["render",p]]);export{u as __pageData,g as default};
